codingChallenges.solution:
num = 7
for i in range(1, 11):
    print(num, "x", i, "=", num * i)

text = "Modern Age Coders"
count = 0
for ch in text:
    if ch.lower() in "aeiou":
        count += 1
print("Vowels in '" + text + "':", count)

secret = 7
guess = 1
while guess <= secret:
    if guess < secret:
        print("Guess:", guess, "- Too low!")
    else:
        print("Guess:", guess, "- Correct!")
    guess += 2

num = 29
if num < 2:
    print(num, "is not a prime number")
else:
    for i in range(2, num):
        if num % i == 0:
            print(num, "is not a prime number")
            break
    else:
        print(num, "is a prime number")

for i in range(1, 5):
    for j in range(1, 5):
        print("(" + str(i) + "," + str(j) + ")", end=" ")
    print()

n = 5
for i in range(1, n + 1):
    for j in range(n - i):
        print(" ", end="")
    for j in range(i):
        print("* ", end="")
    print()
